import{_ as a,o as i,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Upload-Einstellungen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/index.md","filePath":"de-DE/upload/index.md","lastUpdated":1781962217000}'),t={name:"de-DE/upload/index.md"};function d(r,e,s,o,h,c){return i(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="upload-einstellungen" tabindex="-1">Upload-Einstellungen <a class="header-anchor" href="#upload-einstellungen" aria-label="Permalink to &quot;Upload-Einstellungen&quot;">​</a></h1><p>Dieser Abschnitt folgt der gleichen Reihenfolge wie die Kanalverwaltung in den Systemeinstellungen. So kannst du direkt zu dem Speicherdienst springen, den du gerade einrichten möchtest.</p><h2 id="aufbau-dieses-abschnitts" tabindex="-1">Aufbau dieses Abschnitts <a class="header-anchor" href="#aufbau-dieses-abschnitts" aria-label="Permalink to &quot;Aufbau dieses Abschnitts&quot;">​</a></h2><ul><li>Jeder Anbieter hat eine eigene Seite. Die 13 Upload-Kanäle bleiben getrennt, damit die Einrichtungsschritte übersichtlich bleiben.</li><li>Screenshots liegen unter <code>../../image/upload/provider-name/</code> und werden lokal aus der jeweiligen Seite eingebunden.</li><li>Feldnamen bleiben möglichst nah an der Oberfläche von ImgBed; technische Namen wie <code>Endpoint</code>, <code>Client ID</code> oder <code>Refresh Token</code> werden nicht unnötig eingedeutscht.</li></ul><h2 id="kanalubersicht" tabindex="-1">Kanalübersicht <a class="header-anchor" href="#kanalubersicht" aria-label="Permalink to &quot;Kanalübersicht&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="was-dieses-kapitel-abdeckt" tabindex="-1">Was dieses Kapitel abdeckt <a class="header-anchor" href="#was-dieses-kapitel-abdeckt" aria-label="Permalink to &quot;Was dieses Kapitel abdeckt&quot;">​</a></h2><ul><li>Wie du die einzelnen Upload-Kanäle hinzufügst.</li><li>Welche Zugangsdaten, IDs oder Berechtigungen du vorher brauchst.</li><li>Woran du erkennst, dass ein Kanal wirklich für Uploads bereit ist.</li></ul><p>Fehlersuche, Quotenlogik und besondere Hinweise stehen jeweils dort, wo sie für den entsprechenden Dienst wichtig sind.</p>',9)])])}const g=a(t,[["render",d]]);export{b as __pageData,g as default};
